/@media(max-width:768px){    .innertab1,    .report-table{        font-size:12px;    }    .report-title{        font-size:17px;    }}/* Remove Extra Gaps Above Table */table{    margin-top: 5px !important;    margin-bottom: 5px !important;}tr{    margin:0 !important;    padding:0 !important;}td{    padding:6px 6px !important;}/* Fix Download Section Spacing */.download-row td{    padding:5px 0 !important;    line-height:1.2;}/* Remove blank lines */br{    display:none;}/* Center Download Excel Button */.download-row td{    text-align: center !important;}.download-row a{    display: inline-block;    margin: 0 auto;}/* Remove Gap Above Download Section */.download-row{    margin:0 !important;}.download-row td{    padding:4px 0 !important;}/* Remove Top Space From First Table */.innertab1{    margin-top:0 !important;}/* Remove Space From Form/Header Above */form,.report-header{    margin-bottom:5px !important;    padding-bottom:5px !important;}</style><?phpif ($User_Type_ID == 2 || $User_Type_ID == 3)	// $Mysql_Query = "select IMEI, Device_Name, Format_Type from device_register where parent_id = ( SELECT account_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) ORDER BY State desc, Device_Order asc; ";	$Mysql_Query = "SELECT t1.Device_Name,t1.Format_Type,hour(t1.Closing_Time) as Closing_Time, t1.Connect_Feeder,t1.Site_Location,t1.State,IMEI,t1.Group_Name, s.totalCount AS count FROM device_register AS t1 LEFT JOIN ( SELECT Device_Index,State, COUNT(State) totalCount FROM device_register WHERE Parent_ID = ( SELECT account_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) GROUP BY State ) s ON s.State = t1.State where t1.Parent_ID = ( SELECT account_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) ORDER BY count desc,State desc, Device_Order asc";else	// $Mysql_Query = "select IMEI, Device_Name, Format_Type from device_register where parent_id = ( SELECT parent_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) ORDER BY State desc, Device_Order asc; ";	$Mysql_Query = "SELECT t1.Device_Name,t1.Format_Type,hour(t1.Closing_Time) as Closing_Time, t1.Connect_Feeder,t1.Site_Location,t1.State,IMEI,t1.Group_Name, s.totalCount AS count FROM device_register AS t1 LEFT JOIN ( SELECT Device_Index,State, COUNT(State) totalCount FROM device_register WHERE Account_ID = ( SELECT account_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) GROUP BY State ) s ON s.State = t1.State where t1.Account_ID = ( SELECT account_id FROM device_register WHERE IMEI = '" . $IMEI . "' ) ORDER BY count desc,State desc, Device_Order asc";if (!$Mysql_Query_Result = $db->query($Mysql_Query)) {	die($db->error);}$devices = [];$table_name_to_fetch = $Table_Name;if ($Mysql_Query_Result->num_rows >= 1) {	while ($Fetch_Result = $Mysql_Query_Result->fetch_array()) {		$devices[] = [			'IMEI' => $Fetch_Result['IMEI'],			'Device_Name' => $Fetch_Result['Device_Name'],			// 'table_name' => $Fetch_Result['Format_Type'] == 10 ? 'device_data_f10' : ($Fetch_Result['Format_Type'] == 6 ? 'device_data_f6' : 'device_data')			// 'table_name' => $Fetch_Result['Format_Type'] == 1 ? 'device_data' : 'device_data_f'.$Fetch_Result['Format_Type'],			'table_name' => $Fetch_Result['Format_Type'] == 10 || $Fetch_Result['Format_Type'] == 6 ? 'device_data_f' . $Fetch_Result['Format_Type'] : 'device_data',			'Format_Type' => $Fetch_Result['Format_Type']		];		$Group_Name = $Fetch_Result['Group_Name'];	}}// Date Calculation$Date_Range =  getDaysInBetween($_REQUEST['inputDate'], $_REQUEST['inputDate1']);foreach ($Date_Range as $Date_Range_Val) {	foreach ($devices as $device) {		$Date_Range_Val_Final = $Date_Range_Val[0];		$Date_Range_Val_Final1 = date("Y-m-d", $Date_Range_Val_Final);		// Getting 24 hours data		$Date_Range_Val_Final = date("dmY", $Date_Range_Val[0]);		if ($device['Format_Type'] == 3)			$query_24_data = "select DISTINCT(SUBSTRING(Time_S,1,2)) AS Time_24 ,Time_S, Date_S,Record_Index from $Cook_Variable[7].device_data_f3 where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and (Production_Total != '') and Production_Total >'1' group by Time_24 order by Time_24 asc";		else if ($device['Format_Type'] == 2)			$query_24_data = "select DISTINCT(SUBSTRING(Time_S,1,2)) AS Time_24 ,Time_S, Date_S,Record_Index from $Cook_Variable[7].device_data_f2 where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and (PAT_Gen1 != '') and PAT_Gen1 >'1' group by Time_24 order by Time_24 asc";				else			$query_24_data = "select DISTINCT(SUBSTRING(Time_S,1,2)) AS Time_24,Time_S, Date_S,PAT_Gen2,Record_Index from $Cook_Variable[7]." . $device['table_name'] . " where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and PAT_Gen2 != '' and PAT_Gen2 >'1' group by Time_24 order by Time_24 asc";//echo $query_24_data;		if (!$Mysql_Query_Result1 = $db->query($query_24_data)) {			die($db->error);		}		$All_Device_Name_Arr[$device['IMEI']] = $device['Device_Name'];		$Mysql_Record_Count1 = $Mysql_Query_Result1->num_rows;		$MI = 1;		if ($Mysql_Query_Result1->num_rows >= 1) {			$PAT_Total_24 = [];			while ($Fetch_Result1 = $Mysql_Query_Result1->fetch_array()) {				$Fetch_Result2 = $Fetch_Result1;				$PAT_Total_24["k" . $Fetch_Result2['Time_24']] = $Fetch_Result2['Record_Index'];				$All_Date_Arr[$Date_Range_Val_Final][$device['IMEI']] = $Fetch_Result2['Date_S'];				$MI++;			}		}		$PAT_Total_24_Merge[$Date_Range_Val_Final][$device['IMEI']] = array_merge($Time_24_Array, $PAT_Total_24);		//echo "Merge Output ===> ";print_r($PAT_Total_24_Merge[$Date_Range_Val_Final][$device['IMEI']]);		#		#	Getting all the data from DB		#		if ($device['Format_Type'] == 3)			$query = "select Time_S, Date_S,Record_Index,Production_Total,Import_Kwh from $Cook_Variable[7].device_data_f3 where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and (Production_Total != '') and Production_Total >'1' order by Record_Index asc"; // limit 31,18";		else if ($device['Format_Type'] == 2)			$query = "select Time_S, Date_S,PAT_Gen1,PAT_Gen2,Record_Index from $Cook_Variable[7].device_data_f2 where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and (PAT_Gen1 != '') and PAT_Gen1 >'1' order by Record_Index asc"; 		else			$query = "select Time_S, Date_S,PAT_Gen2,Record_Index from $Cook_Variable[7]." . $device['table_name'] . " where IMEI = '" . $device['IMEI'] . "' and Date_S = '" . $Date_Range_Val_Final1 . "' and PAT_Gen2 != '' and PAT_Gen2 >'1' order by Record_Index asc"; // limit 31,18";//echo $query;		if (!$mysql_Query_Result = $db->query($query)) {			die($db->error);		}		$Mysql_Record_Count = $mysql_Query_Result->num_rows;		if ($mysql_Query_Result->num_rows >= 1) {			$MI = 1;			while ($Fetch_Result = $mysql_Query_Result->fetch_array()) {				$Fetch_Result3 = $Fetch_Result;				$Time_First_Seg = substr($Fetch_Result3['Time_S'], 0, 2);				if ($device['Format_Type'] == 3)					$PAT_Total[$Date_Range_Val_Final][$device['IMEI']][$MI] = $Fetch_Result3['Production_Total'];				else if ($device['Format_Type'] == 2)					$PAT_Total[$Date_Range_Val_Final][$device['IMEI']][$MI] = $Fetch_Result3['PAT_Gen1'] + $Fetch_Result3['PAT_Gen2'];				else					$PAT_Total[$Date_Range_Val_Final][$device['IMEI']][$MI] = $Fetch_Result3['PAT_Gen2'];				$PAT_Total_RI[$Date_Range_Val_Final][$device['IMEI']][$MI] = $Fetch_Result3['Record_Index'];				$PAT_Total_Record_Index[$Date_Range_Val_Final][$device['IMEI']][$Fetch_Result3['Record_Index']]  = $MI;				$MI++;			}		}		$Total_Count_DB[$Date_Range_Val_Final][$device['IMEI']] = count($PAT_Total_Record_Index[$Date_Range_Val_Final][$device['IMEI']]);	}} // foreach end	if ($XLS == 0) {?>			<tr class="download-row">    <td colspan="5" align="center">			<!--<b>&nbsp;Please click the below link to Download the