ign="left"><b>18.00-22.00(C2)</b></td>				<!--<td class="tab-head-td" align="left"><b>21.00-22.00 (C3)</b></td> -->				<td class="tab-head-td" align="left"><b>10.00-18.00(C4)</b></td>				<td class="tab-head-td" align="left"><b>5.00 - 6.00( C4)</b></td>				<td class="tab-head-td" align="left"><b>0.00 -5.00(C5)</b></td>				<td class="tab-head-td" align="left"> <b>22.00-24.00 (C5)</b> </td>				<td class="tab-head-td" align="left"><b>Total(Daily)</b></td>			</tr>			<?php			foreach ($Date_Range as $Date_Range_Val) {				$DRVF = $Date_Range_Val[0];				$MI = 1;				$PAT_Total_24_Merge_Prev = '';				$DRVF = date("dmY", $Date_Range_Val[0]);				foreach ($PAT_Total_24_Merge[$DRVF] as $IMEI => $PAT_Total_24_Merge_Dates) {					foreach ($PAT_Total_24_Merge_Dates as $PAT_Total_24_Merge_Key => $PAT_Total_24_Merge_Val) {						#						#	For records which is not available in Table						#						if ($PAT_Total_24_Merge_Val == '') {							$PAT_Total_24_Merge_Val = $PAT_Total_24_Merge_Prev;						}						$PAT_Total_24_Merge_Prev = $PAT_Total_24_Merge_Val;						if ($PAT_Total_24_Merge_Prev == '') {							$PAT_Total_24_Merge_Prev = $PAT_Total_RI[$DRVF][$IMEI][1];						}						//Only for first value						if ($PAT_Total_24_Merge_Key == 'k00' && $PAT_Total_24_Merge_Val == '') {							$PAT_Total_24_Merge_Val = $PAT_Total_RI[$DRVF][$IMEI][1];						}						#						#	Previous Value						#						$PAT_Total_Previous1[$DRVF] = $PAT_Total_Record_Index[$DRVF][$IMEI][$PAT_Total_24_Merge_Val];						$PTP = $PAT_Total_Previous1[$DRVF];						if ($PTP == 1)							$PTP = 1;						else							$PTP = $PAT_Total_Previous1[$DRVF] - 1;						# 24th data calculation							if ($PAT_Total_24_Merge_Key == 'k24'  && $Date_Range_Val_Final1!=date("Y-m-d")) {							$PTP = $Total_Count_DB[$DRVF][$IMEI] - 1;						}						$PAT_Total_Previous[$DRVF] = $PAT_Total[$DRVF][$IMEI][$PTP];						// $PAT_Total_Previous[01062024] = 1699033						#						#	Current Value && Fetching PAT_Gen2						#						$PAT_Total_Current1[$DRVF] = $PAT_Total_Record_Index[$DRVF][$IMEI][$PAT_Total_24_Merge_Val];						// $PAT_Total_Current1[$DRVF] = 1						# 24th data calculation							if ($PAT_Total_24_Merge_Key == 'k24'  && $Date_Range_Val_Final1!=date("Y-m-d")) {							$PAT_Total_Current1[$DRVF] = $Total_Count_DB[$DRVF][$IMEI];						}						$PAT_Total_Current[$DRVF] = $PAT_Total[$DRVF][$IMEI][$PAT_Total_Current1[$DRVF]];						// $PAT_Total_Current[01062024] = 1699033//print_r($PAT_Total_Current[$DRVF]);						#						#	Next Value && Fetching PAT_Gen2						#						$PAT_Total_Next1[$DRVF] = $PAT_Total_Current1[$DRVF] + 1;						// $PAT_Total_Next1[$DRVF] = 2						# 24th data calculation							if ($PAT_Total_24_Merge_Key == 'k24') {							$PAT_Total_Next1[$DRVF] = $Total_Count_DB[$DRVF][$IMEI];						}						//$PAT_Total_Next[$DRVF] = $PAT_Total[$DRVF][$IMEI][$PAT_Total_Next1[$DRVF]];						$PAT_Total_24_Merge_Key." => ".$PAT_Total_Next[$DRVF] = $PAT_Total[$DRVF][$IMEI][$PAT_Total_Next1[$DRVF]];						// K00 => $PAT_Total_Next[01062024] = 1699041						#						#	Combining all the data						#							$PAT_Total_EB_Final[$DRVF][$PAT_Total_24_Merge_Key] = array('Prev' => $PAT_Total_Previous[$DRVF], 'Curr' => $PAT_Total_Current[$DRVF], 'Next' => $PAT_Total_Next[$DRVF]);					}							//echo "Pat EB Total Output ===> ";print_r($PAT_Total_EB_Final[$DRVF]);					// Calculation					// $PT_EB_Fl[$DRVF] = $PAT_Total_EB_Final[$DRVF][$PAT_Total_24_Merge_Key];					$PT_EB_Fl[$DRVF] = $PAT_Total_EB_Final[$DRVF];					$PAT_Total1_06_09[$DRVF] =  (($PT_EB_Fl[$DRVF]['k10']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k10']['Prev'] : $PT_EB_Fl[$DRVF]['k10']['Curr']) - ($PT_EB_Fl[$DRVF]['k06']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k06']['Prev'] : $PT_EB_Fl[$DRVF]['k06']['Curr'])); //6to10					$PAT_Total_06_09[$DRVF]=$PAT_Total1_06_09[$DRVF]>0 && $PAT_Total1_06_09[$DRVF]<8000 ? $PAT_Total1_06_09[$DRVF]:00;					$PAT_Total1_09_18[$DRVF] =  (($PT_EB_Fl[$DRVF]['k18']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k18']['Prev'] : $PT_EB_Fl[$DRVF]['k18']['Curr']) - ($PT_EB_Fl[$DRVF]['k10']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k10']['Prev'] : $PT_EB_Fl[$DRVF]['k10']['Curr']));					$PAT_Total_09_18[$DRVF]=$PAT_Total1_09_18[$DRVF]>0 && $PAT_Total1_09_18[$DRVF]<8000 ? $PAT_Total1_09_18[$DRVF]:00;										$PAT_Total1_05_06[$DRVF] =  (($PT_EB_Fl[$DRVF]['k06']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k06']['Prev'] : $PT_EB_Fl[$DRVF]['k06']['Curr']) - ($PT_EB_Fl[$DRVF]['k05']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k05']['Prev'] : $PT_EB_Fl[$DRVF]['k05']['Curr']));					$PAT_Total_05_06[$DRVF]=$PAT_Total1_05_06[$DRVF]>0 && $PAT_Total1_05_06[$DRVF]<8000 ? $PAT_Total1_05_06[$DRVF]:00;										$PAT_Total1_18_21[$DRVF] =  (($PT_EB_Fl[$DRVF]['k22']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k22']['Prev'] : $PT_EB_Fl[$DRVF]['k22']['Curr']) - ($PT_EB_Fl[$DRVF]['k18']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k18']['Prev'] : $PT_EB_Fl[$DRVF]['k18']['Curr'])); //6pmto10pm					$PAT_Total_18_21[$DRVF]=$PAT_Total1_18_21[$DRVF]>0 && $PAT_Total1_18_21[$DRVF]<8000 ? $PAT_Total1_18_21[$DRVF]:00;										$PAT_Total1_21_22[$DRVF] =  (($PT_EB_Fl[$DRVF]['k22']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k22']['Prev'] : $PT_EB_Fl[$DRVF]['k22']['Curr']) - ($PT_EB_Fl[$DRVF]['k21']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k21']['Prev'] : $PT_EB_Fl[$DRVF]['k21']['Curr']));					$PAT_Total_21_22[$DRVF]=$PAT_Total1_21_22[$DRVF]>0 && $PAT_Total1_21_22[$DRVF]<8000 ? $PAT_Total1_21_22[$DRVF]:00;										$PAT_Total1_22_05_left[$DRVF] =  (($PT_EB_Fl[$DRVF]['k24']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k24']['Prev'] : $PT_EB_Fl[$DRVF]['k24']['Curr']) - ($PT_EB_Fl[$DRVF]['k22']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k22']['Prev'] : $PT_EB_Fl[$DRVF]['k22']['Curr']));					$PAT_Total_22_05_left[$DRVF]=$PAT_Total1_22_05_left[$DRVF]>0 && $PAT_Total1_22_05_left[$DRVF]<8000 ? $PAT_Total1_22_05_left[$DRVF]:00;										$PAT_Total1_22_05_Right[$DRVF] =  (($PT_EB_Fl[$DRVF]['k05']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k05']['Prev'] : $PT_EB_Fl[$DRVF]['k05']['Curr']) - ($PT_EB_Fl[$DRVF]['k00']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k00']['Prev'] : $PT_EB_Fl[$DRVF]['k00']['Curr']));					$PAT_Total_22_05_Right[$DRVF]=$PAT_Total1_22_05_Right[$DRVF]>0 && $PAT_Total1_22_05_Right[$DRVF]<8000 ? $PAT_Total1_22_05_Right[$DRVF]:00;										$PAT_Total1_00_05[$DRVF] =  (($PT_EB_Fl[$DRVF]['k05']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k05']['Prev'] : $PT_EB_Fl[$DRVF]['k05']['Curr']) - ($PT_EB_Fl[$DRVF]['k00']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k00']['Prev'] : $PT_EB_Fl[$DRVF]['k00']['Curr']));					$PAT_Total_00_05[$DRVF]=$PAT_Total1_00_05[$DRVF]>0 && $PAT_Total1_00_05[$DRVF]<8000 ? $PAT_Total1_00_05[$DRVF]:00;										$PAT_Total1_22_24[$DRVF] =  (($PT_EB_Fl[$DRVF]['k24']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k24']['Prev'] : $PT_EB_Fl[$DRVF]['k24']['Curr']) - ($PT_EB_Fl[$DRVF]['k22']['Curr'] == '' ? $PT_EB_Fl[$DRVF]['k22']['Prev'] : $PT_EB_Fl[$DRVF]['k22']['Curr']));					$PAT_Total_22_24[$DRVF]=$PAT_Total1_22_24[$DRVF]>0 && $PAT_Total1_22_24[$DRVF]<8000 ? $PAT_Total1_22_24[$DRVF]:00;										//Total(Daily)	06.00-10.00 (C1)	,18.00-22.00(C2)	,10.00-18.00(C4)						//,5.00 - 6.00( C4),	0.00 -5.00+22.00-24.00 (C5)					$Total_Daily[$DRVF] = $PAT_Total_06_09[$DRVF] + $PAT_Total_18_21[$DRVF] + $PAT_Total_09_18[$DRVF] + $PAT_Total_05_06[$DRVF] +   $PAT_Total_00_05[$DRVF] +   $PAT_Total_22_24[$DRVF];					//Other Peak Hours 					$Other_Peak_Hours[$DRVF] = $PAT_Total_09_18[$DRVF] + $PAT_Total_21_22[$DRVF] + $PAT_Total_05_06[$DRVF];					//Peak Hours					$Peak_Hours[$DRVF] = $PAT_Total_06_09[$DRVF] + $PAT_Total_18_21[$DRVF];					//Night Hours					$Night_Hours[$DRVF] = $PAT_Total_22_05[$DRVF];					// Cumulative Value							$PAT_Total_06_09_CT += $PAT_Total_06_09[$DRVF];					$PAT_Total_09_18_CT += $PAT_Total_09_18[$DRVF];					$PAT_Total_05_06_CT += $PAT_Total_05_06[$DRVF];					$PAT_Total_18_21_CT += $PAT_Total_18_21[$DRVF];					$PAT_Total_21_22_CT += $PAT_Total_21_22[$DRVF];					//$PAT_Total_22_05_CT += $PAT_Total_22_05[$DRVF];					$PAT_Total_22_24_CT += $PAT_Total_22_24[$DRVF];					$PAT_Total_00_05_CT += $PAT_Total_00_05[$DRVF];					$Total_Daily_CT += $Total_Daily[$DRVF];					$Other_Peak_Hours_CT += $Other_Peak_Hours[$DRVF];					$Peak_Hours_CT += $Peak_Hours[$DRVF];					$Night_Hours_CT += $PAT_Total_22_05[$DRVF];					// }					$MI++;					// }					 $Cum = 0;					// foreach ($Date_Range as $Date_Range_Val) {					// 	$DRVF = date("dmY", $Date_Range_Val[0]);					$Total_Daily_Cumulative += $Total_Daily[$DRVF];			?>					<tr>						<td class="tab-head-td1" align="left"><?= $All_Date_Arr[$DRVF][$IMEI] ?></td>						<td class="tab-head-td1" align="left"><?= $All_Device_Name_Arr[$IMEI] ?></td>						<td class="tab-head-td1" align="left"><?= ($PAT_Total_06_09[$DRVF]>=0 && $PAT_Total_06_09[$DRVF]<=8000) ? round($PAT_Total_06_09[$DRVF], 1):'00' ?></td>           												<td class="tab-head-td1" align="left"><?= ($PAT_Total_18_21[$DRVF]>=0 && $PAT_Total_18_21[$DRVF]<=8000) ?round($PAT_Total_18_21[$DRVF], 1):'00' ?></td>						<!--<td class="tab-head-td1" align="left"><?= round($PAT_Total_21_22[$DRVF], 1) ?></td>-->						<td class="tab-head-td1" align="left"><?= ($PAT_Total_9_18[$DRVF]>=0 && $PAT_Total_09_18[$DRVF]<=8000) ?round($PAT_Total_09_18[$DRVF], 1):'00' ?></td>						<td class="tab-head-td1" align="left"><?= round($PAT_Total_05_06[$DRVF], 1) ?></td>						<td class="tab-head-td1" align="left"><?= round($PAT_Total_00_05[$DRVF], 1) ?></td>						<td class="tab-head-td1" align="left"><?= round($PAT_Total_22_24[$DRVF], 1) ?></td>												<td class="tab-head-td1" align="left"><?= round($Total_Daily[$DRVF], 1) ?></td>						<!--<td class="tab-head-td1" align="left"><?= round($Total_Daily_Cumulative, 1) ?></td>								<td class="tab-head-td1" align="left"><?= round($Other_Peak_Hours[$DRVF], 1) ?></td>								<td class="tab-head-td1" align="left"><?= round($Peak_Hours[$DRVF], 1) ?></td>								<td class="tab-head-td1" align="left"><?= round($Night_Hours[$DRVF], 1) ?></td>-->					</tr>			<?php					$Cum++;				}			}			$Total_Daily_Cumulative_Final += $Total_Daily_Cumulative;			?>			<tr>				<td class="tab-head-td1" align="left"><b>Total</b></td>				<td class="tab-head-td1" align="left"><b></b></td>				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_06_09_CT, 1) ?></b></td>				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_18_21_CT, 1) ?></b></td>				<!--<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_21_22_CT, 1) ?></b></td>-->				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_09_18_CT, 1) ?></b></td>				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_05_06_CT, 1) ?></b></td>				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_00_05_CT, 1) ?></b></td>				<td class="tab-head-td1" align="left"><b><?= round($PAT_Total_22_24_CT, 1) ?></b></td>								<td class="tab-head-td1" align="left"><b><?= round($Total_Daily_CT, 1) ?></b></td>				<!--<td class="tab-head-td1" align="left"><b><?= round($Total_Daily_Cumulative_Final, 1) ?></b></td>							<td class="tab-head-td1" align="left"><b><?= round($Other_Peak_Hours_CT, 1) ?></b></td>							<td class="tab-head-td1" align="left"><b><?= round($Peak_Hours_CT, 1) ?></b></td>							<td class="tab-head-td1" align="left"><b><?= round($Night_Hours_CT, 1) ?></b></td>-->			</tr>		</table>	</td></tr><?php?>